/* ----------------------------------------------------------
   getRouteStops(routeId, direction)
   Devuelve la lista ordenada de paradas de un recorrido.
   direction: 'I' (ida) o 'R' (retorno) — default ambos.
   Cada parada: [lat, lon, nombre, stop_id]
   ---------------------------------------------------------- */
function getRouteStops(routeId, direction) {
  const rid = (routeId || '').toUpperCase();
  const rd  = GTFS_STOPS[rid];
  if (!rd) return [];
  if (direction === 'I') return rd.I || [];
  if (direction === 'R') return rd.R || [];
  // Ambos sentidos combinados (sin duplicados por stop_id)
  const seen = new Set();
  const all  = [];
  for (const s of (rd.I || []).concat(rd.R || [])) {
    if (!seen.has(s[3])) { seen.add(s[3]); all.push(s); }
  }
  return all;
}

/* ----------------------------------------------------------
   findNearestStop(routeId, lat, lon, direction)
   Busca la parada más cercana a las coordenadas GPS dadas.
   Retorna { stop_id, name, lat, lon, distanceM, index }
   ---------------------------------------------------------- */
function findNearestStop(routeId, lat, lon, direction) {
  const stops = getRouteStops(routeId, direction);
  if (!stops.length) return null;

  let best = null;
  let bestDist = Infinity;

  stops.forEach((s, i) => {
    const d = haversine(lat, lon, s[0], s[1]);
    if (d < bestDist) {
      bestDist = d;
      best = { stop_id: s[3], name: s[2], lat: s[0], lon: s[1], distanceM: Math.round(d), index: i };
    }
  });
  return best;
}

/* ----------------------------------------------------------
   findNearbyStops(routeId, lat, lon, radiusM, direction)
   Todas las paradas dentro de un radio (metros). Max 5.
   ---------------------------------------------------------- */
function findNearbyStops(routeId, lat, lon, radiusM, direction) {
  radiusM = radiusM || 500;
  const stops = getRouteStops(routeId, direction);
  return stops
    .map((s, i) => ({ stop_id: s[3], name: s[2], lat: s[0], lon: s[1], distanceM: Math.round(haversine(lat, lon, s[0], s[1])), index: i }))
    .filter(s => s.distanceM <= radiusM)
    .sort((a, b) => a.distanceM - b.distanceM)
    .slice(0, 5);
}

/* Haversine: distancia en metros entre dos puntos GPS */
function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

/* ----------------------------------------------------------
   hasRouteStops(routeId)
   Verifica rápido si hay datos de paradas para una ruta.
   ---------------------------------------------------------- */
function hasRouteStops(routeId) {
  return !!GTFS_STOPS[(routeId || '').toUpperCase()];
}

/* ----------------------------------------------------------
   getRouteDirections(routeId)
   Retorna qué sentidos tiene el recorrido.
   ---------------------------------------------------------- */
function getRouteDirections(routeId) {
  const rd = GTFS_STOPS[(routeId || '').toUpperCase()];
  if (!rd) return [];
  const dirs = [];
  if (rd.I && rd.I.length) dirs.push({ dir: 'I', label: 'Ida', origin: rd.I[0][2], dest: rd.I[rd.I.length-1][2], stops: rd.I.length });
  if (rd.R && rd.R.length) dirs.push({ dir: 'R', label: 'Retorno', origin: rd.R[0][2], dest: rd.R[rd.R.length-1][2], stops: rd.R.length });
  return dirs;
}
